import React from "react";
import VideoPanel from "../components/videoPanel";
import BarraHorizontal from "../components/components/barraHorizontal"; // Verifiqué tu estructura de archivos. Es probable que sea './components/barraHorizontal' o '../components/barraHorizontal'. Si este path da error, ajustalo.
import ContenedorLateral from "../components/contenedorLateral";
import ImagenInteractiva from "../components/imagenInteractiva";
import CarruselImagenes from "../components/carruselImagenes";
// import FooterBar from "../components/footerBar"; // ¡ELIMINA ESTA IMPORTACIÓN!

const HomePage = () => {
  return (
    // Asegúrate de que este div padre tiene un 'min-h-screen' o similar si no está en App.js
    // para que el contenido empuje el footer de App.js hacia abajo correctamente.
    // Aunque ya lo tienes, es una buena práctica recordarlo.
    <div className="w-full min-h-screen flex flex-col gap-8 mt-5">
      <VideoPanel height="60vh">
        <video src="/media/homePage/video.webm" autoPlay muted loop />
      </VideoPanel>

      <BarraHorizontal
        texto="EMPRESAS QUE FORJARON EL PAIS"
        height="3vh"
        margenHorizontal="30vw"
        imagen="/media/homePage/barra.png"
      />

      <div className="w-full flex justify-start items-start gap-[0vw] px-[0vw]">
        <div className="mt-[10vh]">
          <ImagenInteractiva
            ancho="30vw"
            imagenDefault="/media/homePage/defaultImage.webp"
            items={[
              {
                icono: "/media/homePage/lightIcon.png",
                subtitulo: "INNOVACIÓN",
                imagen: "/media/homePage/c1.webp",
                texto: "Transformamos ideas en soluciones que marcan la diferencia.",
              },
              {
                icono: "/media/homePage/recicleIcon.png",
                subtitulo: "SOSTENIBILIDAD",
                imagen: "/media/homePage/c2.webp",
                texto: "Comprometidos con un futuro responsable y respetuoso con el planeta",
              },
              {
                icono: "/media/homePage/secureIcon.png",
                subtitulo: "CONFIANZA",
                imagen: "/media/homePage/c3.jpg",
                texto: "Construimos relaciones sólidas basadas en transparencia y compromiso..",
              },
              {
                icono: "/media/homePage/awardIcon.png",
                subtitulo: "EXCELENCIA",
                imagen: "/media/homePage/c4.jpg",
                texto: "Reconocidos por superar estándares y alcanzar la perfección.",
              },
            ]}
          />
        </div>

        <ContenedorLateral
          subtitulo="SEMANA DE ACTIVIDADES"
          texto="Explorá las últimas noticias, actualizaciones y promociones disponibles en nuestra plataforma."
          imagen="/media/homePage/lateral.png"
          ancho="70vw"  
          alto="43.5vw"
          ovaloRedondez="20px"
          cuadroRedondez="10px"
        />
      </div>

      <BarraHorizontal
        texto="RECORRIDOS DE +100 AÑOS"
        height="3vh"
        margenHorizontal="30vw"
        imagen="/media/homePage/barra.png"
      />

      <CarruselImagenes
        altura={600}
        filas={4}
        backendUrl="http://localhost:3000"
        modoPrueba={true}
      />

      {/* Se agrega el componente de Inicio de Sesión - COMENTARIO ORIGINAL, NO TOCADO */}

      {/* Se agrega el FooterBar al final de la página - ¡ELIMINA ESTA LÍNEA! */}
      {/* <FooterBar /> */}
    </div>
  );
};

export default HomePage;
